// Format top tweets for LLM
let tweetBlock = `Total tweets collected: ${allTweets.length}\n\n`;
tweetBlock += "TOP TWEETS BY ENGAGEMENT (KOL signal — sorted high to low):\n\n";
const seen = new Set();
for (const t of allTweets.slice(0, 50)) {
  if (seen.has(t.id)) continue;
  seen.add(t.id);
  const eng = `${t.metrics?.likes||0}❤️ ${t.metrics?.retweets||0}🔁 ${t.metrics?.impressions||0}👁`;
  tweetBlock += `@${t.username} (${t.name}) [${t._label}]\n${eng}\n${t.text}\n\n`;
}
tweetBlock += "\n--- PER-QUERY COUNTS ---\n";
for (const [label, tweets] of Object.entries(sections)) {
  tweetBlock += `${label}: ${tweets.length} tweets\n`;
}

const prompt = "Analyze social signals for this crypto token. Use ONLY the tweet data provided below.\n\n"
  + "TOKEN: " + d.ticker + " / " + d.name + "\n\n"
  + "TWEET DATA:\n" + tweetBlock + "\n\n"
  + "Produce a thorough analysis:\n"
  + "- Discussion Quality (organic vs shills/bots, signal-to-noise %)\n"
  + "- Top Accounts by Reach: LIST EACH HIGH-ENGAGEMENT ACCOUNT BY NAME (@username), follower proxy from impressions, their exact stance and specific claims\n"
  + "- Social Volume (total tweets analyzed, dominant direction, velocity trend)\n"
  + "- Sentiment Breakdown (bullish/bearish/neutral % with specific tweet evidence)\n"
  + "- Community Activity & Tone (degen culture, builder culture, speculative vs conviction)\n"
  + "- Notable KOLs: NAME EVERY ACCOUNT with >500 impressions, their stance, and what specifically they said\n"
  + "- Narrative & Ecosystem Fit\n"
  + "- Fake Token / Scam Alerts\n"
  + "- Overall Social Health with confidence rating\n\n"
  + "IMPORTANT: End your response with these exact structured fields on separate lines:\n"
  + "community_status: [Very Active | Active | Moderate | Low | Dead]\n"
  + "account_quality: [Builders/Researchers | Traders/Degens | Mixed Quality | Promoters/Shills | Unknown]\n"
  + "overall_sentiment: [Strongly Bullish | Bullish | Mixed | Bearish | Strongly Bearish | Unknown]";

return [{ json: { requestBody: { model: "anthropic/claude-sonnet-4-6", messages: [{ role: "user", content: prompt }], max_tokens: 3000 } } }];

// Combine fundamentals + social synthesis outputs
function extractLLM(item) {
  try { if (item.json.content && Array.isArray(item.json.content)) return item.json.content[0].text; } catch(e) {}
  try { return item.json.choices[0].message.content; } catch(e) {}
  return "Unavailable";
}
const items = $input.all();
const tokenData = $("Parse Webhook").first().json;
let fund = "Unavailable", social = "Unavailable";
try { fund = extractLLM(items[0]); } catch(e) {}
try { social = extractLLM(items[1]); } catch(e) {}
return [{ json: Object.assign({}, tokenData, { fundamentals_research: fund, social_research: social }) }];

// Format result for Nash Satoshi webhook callback
const run_id = $("Parse Webhook").item.json.run_id || "";
const resp = $input.all()[0].json;
let result = "";
try {
  if (resp.content && Array.isArray(resp.content)) { result = resp.content[0].text || ""; }
  else if (resp.choices) { result = resp.choices[0].message.content || ""; }
  else { result = JSON.stringify(resp); }
} catch(e) { result = JSON.stringify(resp); }
return [{ json: { webhookBody: { run_id: run_id, state: "DONE", outputs: { analysis_result: result } } } }];

// Build failure webhook body
let run_id = "";
try { run_id = $("Parse Webhook").item.json.run_id || ""; } catch(e) { run_id = "unknown"; }
return [{ json: { webhookBody: { run_id: run_id, state: "FAILED", outputs: {} } } }];

